// Parse payload Asaas + filtra Auto Ads + BUSCA dados do cliente (telefone/email/nome) na API.
// IMPORTANTE: no webhook do Asaas, payment.customer vem como ID (string), SEM telefone/email.
// Por isso buscamos o cliente via GET /v3/customers/{id}.
const body = $('webhook').first().json.body || {};
const event = body.event || '';
const payment = body.payment || {};

const customer_id = (typeof payment.customer === 'string')
  ? payment.customer
  : ((payment.customer || {}).id || null);
const subscription_id = payment.subscription || payment.subscriptionId || null;

let valor_esperado_cents = 49700;
let valor_bump_cents = 59600;
let grupo_auto_ads = '';
let api_key = '';
try {
  const cfg = $('load_config_asaas').first().json;
  valor_esperado_cents = parseInt(cfg.asaas_product_value_cents || '49700', 10);
  grupo_auto_ads = (cfg.asaas_group_name || '').trim();
  api_key = cfg.asaas_api_key || '';
} catch (e) {}

const valor_pago_cents = Math.round((payment.value || 0) * 100);
const ext_ref = String(payment.externalReference || '').toLowerCase();
const eh_auto_ads =
  valor_pago_cents === valor_esperado_cents
  || valor_pago_cents === valor_bump_cents
  || ext_ref.includes('auto-ads')
  || ext_ref.includes('dia1-com-bump');

if (!eh_auto_ads) {
  return [{ json: { skip: true, motivo: 'pagamento_nao_eh_auto_ads', event, valor_pago_cents, ext_ref } }];
}

let novo_status = null;
if (['PAYMENT_CONFIRMED', 'PAYMENT_RECEIVED'].includes(event)) {
  novo_status = 'pago_aguardando_meta';
} else if (['PAYMENT_REFUNDED', 'PAYMENT_CHARGEBACK_REQUESTED', 'PAYMENT_DELETED',
            'SUBSCRIPTION_DELETED', 'SUBSCRIPTION_INACTIVATED'].includes(event)) {
  novo_status = 'inativo';
} else {
  return [{ json: { skip: true, event, motivo: 'evento_ignorado' } }];
}

if (!customer_id) {
  return [{ json: { skip: true, motivo: 'sem_customer_id', event } }];
}
if (!api_key || api_key === 'TODO_PREENCHER') {
  return [{ json: { skip: true, motivo: 'asaas_sem_api_key', event } }];
}

let cust;
try {
  cust = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.asaas.com/v3/customers/${customer_id}`,
    headers: { 'access_token': api_key, 'Content-Type': 'application/json' },
    json: true,
    returnFullResponse: false,
  });
} catch (e) {
  const detalhe = (e && e.response && e.response.body) || (e && e.message) || String(e);
  return [{ json: { skip: true, motivo: 'erro_busca_customer', event, customer_id, detalhe } }];
}

const phoneRaw = cust.mobilePhone || cust.phone || '';
const email = cust.email || '';
const nome = cust.name || '';
let telefone = String(phoneRaw).replace(/\D/g, '');
if (telefone.length >= 10 && !telefone.startsWith('55')) telefone = '55' + telefone;

if (!telefone || telefone.length < 10) {
  return [{ json: { skip: true, motivo: 'telefone_invalido', event, customer_id, email, nome } }];
}

return [{ json: {
  skip: false,
  event, novo_status, telefone, email, nome,
  subscription_id, customer_id, valor_pago_cents, ext_ref,
}}];

// Lê do upsert_cliente (tem o status), não do asaas_set_group (que é no-op com skip)
const r = $('upsert_cliente').first().json;
const status = r.status;
if (status === 'pago_aguardando_meta') {
  return [{ json: { action: 'welcome', cliente: r } }];
} else if (status === 'inativo') {
  return [{ json: { action: 'pausar_campanhas', cliente: r } }];
}
return [{ json: { action: 'noop', cliente: r } }];

const nome = ($('parse_payment').first().json.nome || '').split(' ')[0] || 'aí';
const telefone = $('parse_payment').first().json.telefone;
const BASE = "https://lp.quirkgrowth.com.br/autoads";

const msgs = [
  { text:
      `Oi, ${nome}! 👋 Sou o assistente do Quirk Auto Ads.\n\n` +
      `Pagamento confirmado ✓ Bem-vindo!\n\n` +
      `Antes de subir teu primeiro anúncio, preciso te ajudar a conectar tua conta Meta. Vou te guiar — é rápido.` },
  { text:
      `📋 Montei um guia completo, com print de cada tela e um vídeo, pra você seguir no teu ritmo:\n\n` +
      `${BASE}/onboarding.html\n\n` +
      `Abre esse link, segue o passo a passo, e qualquer dúvida me chama aqui.` },
  { text:
      `💡 Dica: se travar em algum passo, manda um *print* aqui do que você tá vendo na tela. ` +
      `Eu olho a imagem e te falo exatamente o que clicar.\n\n` +
      `Quando terminar de conectar tudo, me manda numa mensagem só:\n` +
      `1️⃣ Nome da tua Fanpage\n` +
      `2️⃣ Teu Ad Account ID (números do Gerenciador)\n\n` +
      `Aí eu valido e libero a criação de campanhas. 🚀` },
];

// Sem imagens no welcome (guia visual completo está na página + email).
return msgs.map((m, i) => ({
  json: { telefone, text: m.text, image_url: null, has_image: false, index: i, total: msgs.length }
}));

// Lista campanhas ACTIVE do cliente e pausa via Meta API
const cliente = $('parse_payment').first().json;
return [{ json: { telefone: cliente.telefone, todo: 'pausar_campanhas_via_meta_api' } }];
// TODO: implementar pause real. Por ora, só marca a intenção.

// LIMITAÇÃO da API do Asaas: groupName NÃO pode ser alterado via PUT/POST após
// a criação do customer (testado em 2026-06-16, várias variantes). Solução:
// configurar o LINK DE PAGAMENTO no painel Asaas pra atribuir o grupo
// automaticamente no momento da venda. Esse Code fica como log/no-op pra
// preservar o fluxo e estrutura.
//
// Se o Asaas algum dia liberar o endpoint, basta destrocar este code pelo
// original (git history → asaas_set_group antes do c_de_referência).

const customer_id = $('parse_payment').first().json.customer_id;
const cfg = $('load_config_asaas').first().json;
const grupo_nome = (cfg.asaas_group_name || '').trim();

return [{
  json: {
    ok: false,
    skip: true,
    customer_id,
    motivo: 'asaas_group_api_limitation',
    nota: 'Asaas não permite alterar groupName via API após criação. Configure o LINK DE PAGAMENTO no painel Asaas pra atribuir grupo "' + grupo_nome + '" automaticamente.',
  }
}];

